<?php

declare(strict_types=1);

namespace grupo_donato_gestao\Services;

use grupo_donato_gestao\Config\Constants;

class AddressService extends CustomerDataService
{
    private $model;private $accounts;
    public function __construct(int $unit_id,int $actor_id=0,?object $login_user=null){parent::__construct($unit_id,$actor_id,$login_user);$this->model=model('grupo_donato_gestao\\Models\\Gd_addresses_model');$this->accounts=model('grupo_donato_gestao\\Models\\Gd_customer_accounts_model');}
    public function save(array $input,int $id=0,bool $duplicate_override=false):int{$old=$id?$this->model->get_scoped($id,$this->unit_id):null;if($id&&!$old)throw new \DomainException('gd_record_not_found');$account=(int)($input['account_id']??0);if(!$this->accounts->get_scoped($account,$this->unit_id))throw new \DomainException('gd_invalid_account');$type=(string)($input['address_type']??'');$status=(string)($input['status']??'active');if(!in_array($type,Constants::ADDRESS_TYPES,true)||!in_array($status,Constants::ADDRESS_STATUSES,true))throw new \DomainException('gd_invalid_value');$primary=!empty($input['is_primary'])?1:0;$postal=DataNormalizationService::text($input['postal_code']??'');$street=DataNormalizationService::text($input['street']??'');$number=DataNormalizationService::text($input['number']??'');$postalNormalized=$postal?DataNormalizationService::postal($postal):null;$duplicate=$this->db->table($this->db->prefixTable('gd_addresses'))->where('unit_id',$this->unit_id)->where('account_id',$account)->where('deleted',0)->where('status','active')->where('postal_code_normalized',$postalNormalized)->where('street',$street?:null)->where('number',$number?:null);if($id)$duplicate->where('id !=',$id);$duplicateRow=($postalNormalized||$street)?$duplicate->get(1)->getRow():null;if($duplicateRow&&!$duplicate_override)throw new \DomainException('gd_duplicate_address');$data=$this->stamp(['unit_id'=>$this->unit_id,'account_id'=>$account,'address_type'=>$type,'postal_code'=>$postal?:null,'postal_code_normalized'=>$postalNormalized,'street'=>$street?:null,'number'=>$number?:null,'complement'=>DataNormalizationService::text($input['complement']??'')?:null,'district'=>DataNormalizationService::text($input['district']??'')?:null,'city'=>DataNormalizationService::text($input['city']??'')?:null,'state'=>DataNormalizationService::text($input['state']??'')?:null,'country'=>DataNormalizationService::text($input['country']??'')?:null,'is_primary'=>$primary,'status'=>$status],$id===0);$table=$this->db->prefixTable('gd_addresses');$previousPrimary=$primary&&$status==='active'?$this->db->table($table)->where('account_id',$account)->where('unit_id',$this->unit_id)->where('deleted',0)->where('status','active')->where('is_primary',1)->where('id !=',$id?:0)->get(1)->getRow():null;$now=function_exists('get_current_utc_time')?get_current_utc_time():gmdate('Y-m-d H:i:s');$this->db->transStart();if($primary&&$status==='active'){$this->db->table($table)->where('account_id',$account)->where('unit_id',$this->unit_id)->where('deleted',0)->where('id !=',$id?:0)->update(['is_primary'=>0,'updated_at'=>$now,'updated_by'=>$this->actor_id?:null]);}$save=(int)$this->model->ci_save($data,$id);$this->db->transComplete();if(!$save||$this->db->transStatus()===false)throw new \RuntimeException('save_failed');$this->audit_change($id?'update':'create','address',$save,$old?(array)$old:null,(array)$this->model->get_scoped($save,$this->unit_id));if($previousPrimary){$this->audit_change('primary_change','address',$save,null,null,['previous_address_id'=>(int)$previousPrimary->id]);}if($duplicateRow&&$duplicate_override){$this->audit_change('duplicate_override','address',$save,null,null,['matched_address_id'=>(int)$duplicateRow->id]);}return $save;}
    public function delete(int $id,string $reason):void{$row=$this->model->get_scoped($id,$this->unit_id);if(!$row)throw new \DomainException('gd_record_not_found');if(DataNormalizationService::text($reason)==='')throw new \DomainException('gd_delete_reason_required');$this->model->delete($id);$this->audit_change('delete','address',$id,(array)$row,null,['reason'=>$reason]);}
}
